#include<bits/stdc++.h>
using namespace std;
long long n,f[1000010],dp[1000010],d[1000010],fa[1000010],cnt[1000010],rt[1000010];
vector<long long> mp[1000010],vec[1000010];
bool v[1000010];
const long long mod=1e9+7;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y>>=1;
    }
    return ans;
}
void dfs(long long x,long long fa=0)
{
    d[x]=d[fa]+1;
    ::fa[x]=fa;
    vec[d[x]].push_back(x);
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            f[i]=1ll*f[x]*fastpow((long long)(mp[x].size())-(long long)(fa!=0),mod-2)%mod;
            dfs(i,x);
            if(mp[i].size()==1)
            {
                v[x]=true;
            }
        }
    }
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    f[1]=1;
    dfs(1);
    rt[1]=1;
    for(long long i=1;i<=n;i++)
    {
        for(long long j:vec[i])
        {
            rt[j]=rt[fa[j]];
            dp[j]=dp[rt[j]];
            if(v[j])
            {
                cnt[rt[j]]++;
            }
        }
        for(long long j:vec[i])
        {
            if(mp[j].size()>1&&cnt[rt[j]]>1)
            {
                dp[j]++;
                rt[j]=j;
            }
        }
        for(long long j:vec[i])
        {
            if(v[j])
            {
                cnt[rt[fa[j]]]--;
            }
        }
    }
    long long ans=0;
    for(long long i=2;i<=n;i++)
    {
        if(mp[i].size()==1)
        {
            ans+=f[i]*dp[i]%mod;
            ans%=mod;
        }
    }
    printf("%lld",ans);
    return 0;
}
